#include <stdio.h>
#include <stdlib.h>
typedef struct Node {
    int value;
    struct Node* next;
    struct Node* prev;
} Node;

void insertAtIndex(Node** head, int index, int value) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->value = value;
    newNode->next = NULL;
    newNode->prev = NULL;

    if (*head == NULL || index == 0) {
        newNode->next = *head;
        if (*head != NULL) {
            (*head)->prev = newNode;
        }
        *head = newNode;
    } else {
        Node* iter = *head;
        for (int i = 0; i < index - 1; i++) {
            iter = iter->next;
        }

        Node* A = iter;
        Node* B = iter->next;

        A->next = newNode;
        if (B != NULL) {
            B->prev = newNode;
        }

        newNode->next = B;
        newNode->prev = A;
    }
}

void printValues(Node* head) {
    if (head == NULL) {
        return;
    } else {
        Node* current = head;
        while (current != NULL) {
            printf("%d ", current->value);
            current = current->next;
        }
        printf("\n");
    }
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N, index, value;
        scanf("%d %d", &N, &index);
        Node* head = NULL;
        for (int i = 0; i < N; i++) {
            scanf("%d", &value);
            insertAtIndex(&head, i, value);
        }
        insertAtIndex(&head, index, 99);
        printValues(head);
    }
    return 0;
}

