import java.util.Scanner;

class Node {
    int value;
    Node next;
    Node prev;

    public Node(int value) {
        this.value = value;
        this.next = null;
        this.prev = null;
    }
}

class Main {
    public static void insertAtIndex(Node head, int index, int value, Node[] headRef) {
        Node newNode = new Node(value);

        if (head == null || index == 0) {
            newNode.next = head;
            if (head != null) {
                head.prev = newNode;
            }
            headRef[0] = newNode;
        } else {
            Node iter = head;
            for (int i = 0; i < index - 1; i++) {
                iter = iter.next;
            }

            Node A = iter;
            Node B = iter.next;

            A.next = newNode;
            if (B != null) {
                B.prev = newNode;
            }

            newNode.next = B;
            newNode.prev = A;
        }
    }

    public static void printValues(Node head) {
        if (head == null) {
            return;
        } else {
            Node current = head;
            while (current != null) {
                System.out.print(current.value + " ");
                current = current.next;
            }
            System.out.println();
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int N = scanner.nextInt();
            int index = scanner.nextInt();
            Node head = null;
            Node[] headRef = new Node[1];
            headRef[0] = head;
            for (int i = 0; i < N; i++) {
                int value = scanner.nextInt();
                insertAtIndex(headRef[0], i, value, headRef);
                head = headRef[0];
            }
            insertAtIndex(headRef[0], index, 99, headRef);
            printValues(headRef[0]);
        }
    }
}

